50:     (
51:         $($Kind:ident($AstTy:ty) {
52:             $kind_name:expr;
53:             $(one
54:                 fn $mut_visit_ast:ident;
55:                 fn $visit_ast:ident;
56:                 fn $ast_to_string:path;
57:             )?
58:             $(many
