419: impl InvocationKind {
420:     fn placeholder_visibility(&self) -> Option<ast::Visibility> {
421:         // HACK: For unnamed fields placeholders should have the same visibility as the actual
422:         // fields because for tuple structs/variants resolve determines visibilities of their
423:         // constructor using these field visibilities before attributes on them are expanded.
424:         // The assumption is that the attribute expansion cannot change field visibilities,
425:         // and it holds because only inert attributes are supported in this position.
426:         match self {
427:             InvocationKind::Attr { item: Annotatable::FieldDef(field), .. }
428:             | InvocationKind::Derive { item: Annotatable::FieldDef(field), .. }
429:                 if field.ident.is_none() =>
430:             {
431:                 Some(field.vis.clone())
432:             }
433:             _ => None,
434:         }
435:     }
