61: impl<'a> ParserAnyMacro<'a> {
62:     pub(crate) fn make(mut self: Box<ParserAnyMacro<'a>>, kind: AstFragmentKind) -> AstFragment {
63:         let ParserAnyMacro {
64:             site_span,
65:             macro_ident,
66:             ref mut parser,
67:             lint_node_id,
68:             arm_span,
69:             is_trailing_mac,
70:             is_local,
71:         } = *self;
72:         let snapshot = &mut parser.create_snapshot_for_diagnostic();
73:         let fragment = match parse_ast_fragment(parser, kind) {
74:             Ok(f) => f,
75:             Err(err) => {
76:                 let guar = diagnostics::emit_frag_parse_err(
77:                     err, parser, snapshot, site_span, arm_span, kind,
78:                 );
79:                 return kind.dummy(site_span, guar);
80:             }
81:         };
82: 
83:         // We allow semicolons at the end of expressions -- e.g., the semicolon in
84:         // `macro_rules! m { () => { panic!(); } }` isn't parsed by `.parse_expr()`,
85:         // but `m!()` is allowed in expression positions (cf. issue #34706).
86:         if kind == AstFragmentKind::Expr && parser.token == token::Semi {
87:             if is_local {
88:                 parser.psess.buffer_lint(
89:                     SEMICOLON_IN_EXPRESSIONS_FROM_MACROS,
90:                     parser.token.span,
91:                     lint_node_id,
92:                     errors::TrailingMacro { is_trailing: is_trailing_mac, name: macro_ident },
93:                 );
94:             }
95:             parser.bump();
96:         }
97: 
98:         // Make sure we don't have any tokens left to parse so we don't silently drop anything.
99:         let path = ast::Path::from_ident(macro_ident.with_span_pos(site_span));
100:         ensure_complete_parse(parser, &path, kind.name(), site_span);
